  relatedSlugs: ["mombasa-port-as-industrial-gateway-manufacturing-opportunities-in-kenyas-coastal","eac-manufacturing-integration-how-kenya-is-building-a-regional-industrial-base","kenyas-printing-and-publishing-industry-adapting-to-a-digital-first-marketplace"],
